24	    func getElapsedInterval() -> LocalizedStringResource {
25	        let interval = Calendar.current.dateComponents([.second, .minute, .hour], from: self, to: .now)
26	        if let hours = interval.hour, hours > 0 {
27	            return .Localization.hoursAgo(hours: hours)
28	        } else if let minutes = interval.minute, minutes > 0 {
29	            return .Localization.minutesAgo(minutes: minutes)
30	        } else if let seconds = interval.second, seconds > 0 {
31	            return .Localization.secondsAgo(seconds: seconds)
32	        } else {
33	            return ""
34	        }
35	    }
